ListResponseModel listResponseModelFromJson(String str) => ListResponseModel.fromJson(json.decode(str));
String listResponseModelToJson(ListResponseModel data) => json.encode(data.toJson());
class ListResponseModel {
  ListResponseModel({
      num? success, 
      String? message, 
      String? totalCount, 
      List<ListData>? listData,}){
    _success = success;
    _message = message;
    _totalCount = totalCount;
    _listData = listData;
}

  ListResponseModel.fromJson(dynamic json) {
    _success = json['success'];
    _message = json['message'];
    _totalCount = json['totalCount'];
    if (json['data'] != null) {
      _listData = [];
      json['data'].forEach((v) {
        _listData?.add(ListData.fromJson(v));
      });
    }
  }
  num? _success;
  String? _message;
  String? _totalCount;
  List<ListData>? _listData;
ListResponseModel copyWith({  num? success,
  String? message,
  String? totalCount,
  List<ListData>? listData,
}) => ListResponseModel(  success: success ?? _success,
  message: message ?? _message,
  totalCount: totalCount ?? _totalCount,
  listData: listData ?? _listData,
);
  num? get success => _success;
  String? get message => _message;
  String? get totalCount => _totalCount;
  List<ListData>? get listData => _listData;

  Map<String, dynamic> toJson() {
    final map = <String, dynamic>{};
    map['success'] = _success;
    map['message'] = _message;
    map['totalCount'] = _totalCount;
    if (_listData != null) {
      map['data'] = _listData?.map((v) => v.toJson()).toList();
    }
    return map;
  }

}

